mapper.select:
SELECT br.record_id, br.book_id, br.reader_id, br.borrow_time, br.due_time, br.return_time, br.overdue_days, br.overdue_fee, br.operator_id, br.status, b.book_no, b.book_name, b.category_id, r.reader_no, r.reader_name, r.reader_type, a.admin_name FROM borrow_record br LEFT JOIN book b ON br.book_id = b.book_id LEFT JOIN reader r ON br.reader_id = r.reader_id LEFT JOIN admin a ON br.operator_id = a.admin_id WHERE 1=1
AND b.book_no LIKE CONCAT('%', #{query.bookNo}, '%')
AND b.book_name LIKE CONCAT('%', #{query.bookName}, '%')
AND (r.reader_no LIKE CONCAT('%', #{query.readerNo}, '%') OR r.reader_name LIKE CONCAT('%', #{query.readerNo}, '%'))
AND r.reader_name LIKE CONCAT('%', #{query.readerName}, '%')
AND br.status = #{query.status}
AND br.borrow_time >= #{query.startTime}
AND br.borrow_time <= #{query.endTime}
ORDER BY br.borrow_time DESC
